{
  "tool1_superset": {
    "github_url": {
      "claim": "https://github.com/superset-sh/superset",
      "status": "CONFIRMED",
      "actual": "https://github.com/superset-sh/superset"
    },
    "stars": {
      "claim": "12,399",
      "status": "MINOR DISCREPANCY (timing)",
      "actual": "12,400 (GitHub API). Off by 1, consistent with normal growth since README was written."
    },
    "forks": {
      "claim": "1,076",
      "status": "CONFIRMED",
      "actual": "1,076"
    },
    "issues": {
      "claim": "323 (2.6%)",
      "status": "MINOR DISCREPANCY (timing)",
      "actual": "324 open issues. Off by 1. The 2.6% ratio (issues/stars) still holds: 324/12400 = 2.6%."
    },
    "language": {
      "claim": "TypeScript",
      "status": "CONFIRMED",
      "actual": "TypeScript"
    },
    "license": {
      "claim": "Other",
      "status": "CONFIRMED",
      "actual": "GitHub classifies as 'Other'. Actual license is Elastic License 2.0 (ELv2), which is not OSI-approved, hence GitHub's 'Other' classification. Claim matches GitHub's displayed value."
    },
    "platform": {
      "claim": "macOS (Windows/Linux untested)",
      "status": "CONFIRMED",
      "actual": "README Requirements table states 'macOS (Windows/Linux untested)'. Install section: 'Builds for Windows and Linux are not yet available.'"
    },
    "website": {
      "claim": "https://superset.sh/",
      "status": "CONFIRMED",
      "actual": "https://superset.sh/ (live, redirects to marketing site)"
    },
    "backing": {
      "claim": "YC",
      "status": "CONFIRMED",
      "actual": "Pricing page footer links to https://www.ycombinator.com/companies/superset/jobs, confirming YC backing."
    },
    "features": {
      "1_cli_sdk_mcp": {
        "claim": "CLI + TypeScript SDK + MCP server (3 access surfaces)",
        "status": "CONFIRMED",
        "details": "README 'More Than a Desktop App' table lists CLI, TypeScript SDK (@superset_sh/sdk on npm), and MCP Server as the three programmatic access surfaces alongside the desktop app."
      },
      "2_automations": {
        "claim": "Automations (schedule agent sessions)",
        "status": "CONFIRMED",
        "details": "README Features table: 'Automations | Run agent sessions on a schedule'. Also listed in pricing comparison table."
      },
      "3_slack_linear": {
        "claim": "Slack & Linear integration",
        "status": "CONFIRMED",
        "details": "README: 'Slack & Linear | Spin up workspaces from Slack messages or Linear issues'. Pricing page lists both Slack integration and Linear integration as features (Pro+ tier)."
      },
      "4_browser_ports": {
        "claim": "In-app browser + port detection",
        "status": "CONFIRMED",
        "details": "README: 'In-App Browser & Ports | Preview running dev servers, with ports detected per workspace'."
      },
      "5_custom_agents": {
        "claim": "Custom agent support with icons",
        "status": "CONFIRMED",
        "details": "README: 'Custom Agents | Add your own terminal agents with custom icons'. Also: 'Custom agents: add any terminal agent with its own icon and it works like a built-in'."
      },
      "6_preset_agents": {
        "claim": "12+ preset agents (Amp, Claude Code, Codex, Cursor, Droid, Gemini, Copilot, Mastra, Mistral Vibe, OpenCode, Pi, Polygraph)",
        "status": "CONFIRMED",
        "details": "README 'Supported Agents' table lists exactly these 12 with 'Fully supported' status: Amp Code, Claude Code, OpenAI Codex CLI, Cursor Agent, Droid, Gemini CLI, GitHub Copilot, Mastra Code, Mistral Vibe, OpenCode, Pi, Polygraph. Plus 'Any other CLI agent | Works without configuration'."
      }
    }
  },
  "tool2_cmux": {
    "github_url": {
      "claim": "https://github.com/manaflow-ai/cmux",
      "status": "CONFIRMED",
      "actual": "https://github.com/manaflow-ai/cmux"
    },
    "stars": {
      "claim": "24,412",
      "status": "MINOR DISCREPANCY (timing)",
      "actual": "24,413 (GitHub API). Off by 1, consistent with normal growth since README was written."
    },
    "forks": {
      "claim": "1,970",
      "status": "CONFIRMED",
      "actual": "1,970"
    },
    "issues": {
      "claim": "3,446 (14.1%)",
      "status": "MINOR DISCREPANCY (timing)",
      "actual": "3,444 open issues. Off by 2. The 14.1% ratio (issues/stars) still holds: 3444/24413 = 14.1%."
    },
    "language": {
      "claim": "Swift",
      "status": "CONFIRMED",
      "actual": "Swift"
    },
    "license": {
      "claim": "GPL",
      "status": "DISCREPANCY",
      "actual": "GitHub classifies as 'Other'. The LICENSE file is dual-licensed: (1) open source under GPL-3.0-or-later, and (2) a commercial license option. GitHub reports 'Other' because the dual-license structure does not resolve to a single SPDX identifier. The project's own README says 'Open source — Free and GPL-licensed' and 'GPL-licensed', so the claim 'GPL' matches the project's self-description but NOT GitHub's displayed license field ('Other'). If the awesome-agent-ide README is meant to mirror GitHub's license badge, it should say 'Other'."
    },
    "platform": {
      "claim": "macOS only",
      "status": "CONFIRMED",
      "actual": "Website FAQ: 'macOS only, for now.' README: 'A Ghostty-based macOS terminal'. DMG download is macOS-only. iOS app exists in beta (TestFlight)."
    },
    "website": {
      "claim": "https://cmux.com/",
      "status": "CONFIRMED",
      "actual": "https://cmux.com/ (live, product landing page)"
    },
    "features": {
      "1_ghostty_libghostty": {
        "claim": "Built on Ghostty/libghostty (GPU rendering)",
        "status": "CONFIRMED",
        "details": "README: 'GPU-accelerated — Powered by libghostty for smooth rendering'. Website FAQ: 'It uses libghostty as a library for terminal rendering, the same way apps use WebKit for web views. Ghostty is a standalone terminal; cmux is a different app built on top of its rendering engine.' Not a fork — uses libghostty as a library."
      },
      "2_native_swift_appkit": {
        "claim": "Native Swift/AppKit (not Electron)",
        "status": "CONFIRMED",
        "details": "README: 'Native macOS app — Built with Swift and AppKit, not Electron. Fast startup, low memory.' Website FAQ: 'cmux is a native Swift + AppKit app.'"
      },
      "3_notification_system": {
        "claim": "Notification system (OSC 9/99/777, blue ring, cmux notify CLI)",
        "status": "CONFIRMED",
        "details": "README: 'The notification system picks up terminal sequences (OSC 9/99/777) and has a CLI (cmux notify) you can wire into agent hooks.' Also: 'Panes get a blue ring and tabs light up when coding agents need your attention.' Website FAQ confirms OSC 9/99/777 escape sequences and cmux CLI."
      },
      "4_in_app_browser": {
        "claim": "In-app browser (agent-browser API)",
        "status": "CONFIRMED",
        "details": "README: 'In-app browser — Split a browser alongside your terminal with a scriptable API ported from agent-browser (vercel-labs/agent-browser).' Website FAQ: 'navigate, snapshot the DOM, click, type, evaluate JavaScript, and read console and network activity over the same socket API.'"
      },
      "5_ssh": {
        "claim": "SSH (cmux ssh user@remote)",
        "status": "CONFIRMED",
        "details": "README: 'cmux ssh user@remote creates a workspace for a remote machine. Browser panes route through the remote network so localhost just works.'"
      },
      "6_claude_code_teams": {
        "claim": "Claude Code Teams (cmux claude-teams)",
        "status": "CONFIRMED",
        "details": "README: 'cmux claude-teams runs Claude Code's teammate mode with one command. Teammates spawn as native splits with sidebar metadata and notifications. No tmux required.'"
      },
      "7_cli_socket_api": {
        "claim": "CLI + socket API",
        "status": "CONFIRMED",
        "details": "README: 'Programmable — CLI and socket API to create workspaces, split panes, send keystrokes, and automate the browser.' Website FAQ: 'Every action is available through the cmux CLI and a Unix socket.'"
      },
      "8_ghostty_config_compatible": {
        "claim": "Ghostty config compatible",
        "status": "CONFIRMED",
        "details": "README: 'Ghostty compatible — Reads your existing ~/.config/ghostty/config for themes, fonts, and colors.' Website FAQ: 'Terminal rendering uses your Ghostty config, so themes, fonts, colors, and cursor carry over directly.'"
      }
    }
  },
  "summary": {
    "superset": {
      "stats_confirmed": "Forks, language, license, platform, website, backing all CONFIRMED. Stars off by 1 (12,400 vs 12,399). Issues off by 1 (324 vs 323). Both are timing-related and percentages still hold.",
      "features_confirmed": "All 6 feature claims CONFIRMED.",
      "discrepancies": [
        "Stars: 12,400 actual vs 12,399 claimed (minor, timing)",
        "Issues: 324 actual vs 323 claimed (minor, timing)"
      ]
    },
    "cmux": {
      "stats_confirmed": "Forks, language, platform, website all CONFIRMED. Stars off by 1 (24,413 vs 24,412). Issues off by 2 (3,444 vs 3,446). Both timing-related, percentages still hold.",
      "features_confirmed": "All 8 feature claims CONFIRMED.",
      "discrepancies": [
        "License: GitHub shows 'Other' but claim says 'GPL'. Actual license is GPL-3.0-or-later (dual-licensed with commercial option). Claim matches project self-description but not GitHub's classification.",
        "Stars: 24,413 actual vs 24,412 claimed (minor, timing)",
        "Issues: 3,444 actual vs 3,446 claimed (minor, timing)"
      ]
    }
  }
}

