{
  "tool1_orca": {
    "github_url": {
      "claim": "https://github.com/stablyai/orca",
      "status": "CONFIRMED"
    },
    "stars": {
      "claim": "18,327",
      "status": "DISCREPANCY",
      "correct_value": "18,365 (GitHub API shows 18,365 as of 2026-07-14; website shows '18.3k')"
    },
    "forks": {
      "claim": "1,448",
      "status": "DISCREPANCY",
      "correct_value": "1,449"
    },
    "issues": {
      "claim": "1,361 (7.4%)",
      "status": "DISCREPANCY",
      "correct_value": "1,367 open issues. The 7.4% ratio (issues/stars) remains approximately correct: 1367/18365 = 7.4%. The raw issue count has grown by 6."
    },
    "language": {
      "claim": "TypeScript",
      "status": "CONFIRMED"
    },
    "license": {
      "claim": "MIT",
      "status": "CONFIRMED",
      "details": "MIT License per GitHub repo; LICENSE file present"
    },
    "platform": {
      "claim": "macOS · Windows · Linux · iOS · Android",
      "status": "CONFIRMED",
      "details": "Desktop app runs on macOS, Windows, Linux (README badge confirms). Mobile companion app available on iOS (App Store + TestFlight) and Android (APK). Website says 'Also on macOS, Windows & Linux' and 'Get the mobile companion for iOS or Android'. Note: iOS/Android are companion apps for monitoring/steering agents, not the full IDE."
    },
    "website": {
      "claim": "https://www.onorca.dev/",
      "status": "CONFIRMED",
      "details": "Website loads correctly at www.onorca.dev. README also links to onorca.dev (both resolve to the same site)."
    },
    "feature_claims": {
      "1_design_mode": {
        "claim": "Design Mode (click UI elements in Chromium to send HTML/CSS/screenshot to agent)",
        "status": "CONFIRMED",
        "details": "README: 'Click any UI element in a real Chromium window to send its HTML, CSS, and a cropped screenshot straight into your agent's prompt.' Docs at /docs/browser/design-mode."
      },
      "2_ssh_worktrees": {
        "claim": "SSH Worktrees (run agents on remote machines)",
        "status": "CONFIRMED",
        "details": "README: 'Run agents on a beefy remote box with full file editing, git, and terminals — auto-reconnect and port forwarding included.' Docs at /docs/ssh."
      },
      "3_computer_use": {
        "claim": "Computer Use (agents operate desktop apps)",
        "status": "CONFIRMED",
        "details": "README: 'Let agents operate desktop apps and visible UI when a workflow needs real interaction.' Docs at /docs/cli/computer-use. Also has .github/workflows/computer-e2e.yml CI workflow."
      },
      "4_mobile_companion": {
        "claim": "Mobile companion app (iOS + Android)",
        "status": "CONFIRMED",
        "details": "README lists iOS App Store (id6766130217), TestFlight, and Android APK 0.0.27. Website confirms 'Get the mobile companion for iOS or Android.'"
      },
      "5_annotate_ai_diffs": {
        "claim": "Annotate AI Diffs (comment on diff lines)",
        "status": "CONFIRMED",
        "details": "README: 'Drop comments on any diff line and ship them back to the agent — review, edit, and commit without leaving Orca.' Docs at /docs/review/annotate-ai-diff."
      },
      "6_github_linear_integration": {
        "claim": "GitHub & Linear native integration",
        "status": "CONFIRMED",
        "details": "README: 'Browse PRs, issues, and project boards in-app — open a worktree from any task and review without a context switch.' Docs at /docs/review/linear."
      },
      "7_daily_releases": {
        "claim": "Daily releases",
        "status": "CONFIRMED",
        "details": "README: 'we ship daily, so this list is perpetually behind. The changelog is the real feature list.' Links to GitHub releases as the feature list."
      }
    },
    "tool2_emdash": {
      "github_url": {
        "claim": "https://github.com/generalaction/emdash",
        "status": "CONFIRMED"
      },
      "stars": {
        "claim": "5,149",
        "status": "CONFIRMED",
        "details": "GitHub API shows exactly 5,149"
      },
      "forks": {
        "claim": "534",
        "status": "CONFIRMED",
        "details": "GitHub API shows exactly 534"
      },
      "issues": {
        "claim": "132 (2.6%)",
        "status": "CONFIRMED",
        "details": "GitHub API shows exactly 132 open issues. 132/5149 = 2.6% ratio matches."
      },
      "language": {
        "claim": "TypeScript",
        "status": "CONFIRMED"
      },
      "license": {
        "claim": "Apache-2.0",
        "status": "CONFIRMED",
        "details": "GitHub shows 'Apache License 2.0'; LICENSE.md file present"
      },
      "platform": {
        "claim": "macOS · Windows · Linux",
        "status": "CONFIRMED",
        "details": "README installation table lists all three: macOS (brew/Apple Silicon/Intel), Windows (Installer/Portable), Linux (AppImage/Debian). Website confirms 'On macOS, Windows, and Linux.'"
      },
      "website": {
        "claim": "https://emdash.sh/",
        "status": "DISCREPANCY",
        "correct_value": "emdash.sh now redirects to emdash.ai. The GitHub README still links to emdash.sh/download and emdash.sh/docs (which redirect to emdash.ai equivalents), but the canonical website URL is now https://emdash.ai/. The sitemap.xml is at emdash.ai/sitemap.xml."
      },
      "backing": {
        "claim": "YC W26",
        "status": "CONFIRMED",
        "details": "GitHub README has 'Y Combinator W26' badge. Website shows 'Backed by Y-Combinator'."
      },
      "feature_claims": {
        "1_emdash_port_injection": {
          "claim": "$EMDASH_PORT injection (port collision solution)",
          "status": "CONFIRMED",
          "details": "Found in project-config docs (https://emdash.ai/docs/project-config). EMDASH_PORT is an environment variable injected into task scripts as 'Base port for a 10-port range'. Example: PORT=$EMDASH_PORT DB_PORT=$((EMDASH_PORT + 1)) pnpm dev. Also supports Docker Compose: '${EMDASH_PORT:-5432}:5432'. This solves port collisions when running multiple parallel agents each with their own dev server. NOT mentioned in the GitHub README or main docs overview—only in the project-config docs page."
