        },
        "license": {
          "status": "DISCREPANCY",
          "claim": "unclear/unknown",
          "actual": "MIT License — confirmed on both the stravu/crystal and Nimbalyst/nimbalyst GitHub repos. The Nimbalyst README states: 'This repository is licensed under the MIT License.'"
        }
      },
      "feature_claims": {
        "1_worktree_as_session_primitive": {
          "status": "CONFIRMED",
          "evidence": "Crystal README: 'Run multiple Codex and Claude Code AI sessions in parallel git worktrees.' Nimbalyst README lists 'Leverage worktrees' as a developer feature and 'Git worktree isolation for safer parallel AI coding sessions.'"
        },
        "2_inline_diffs_visual_sidebar_gui_merge": {
          "status": "CONFIRMED",
          "evidence": "Nimbalyst README: 'Approve the coding agent's changes in red/green WYSIWYG, edit, annotate.' Also: 'Accept/reject AI changes — step through suggested AI edits and accept or reject.' FileList and DraggableProjectTreeView components exist in the codebase."
        },
        "3_ios_companion_app": {
          "status": "CONFIRMED",
          "evidence": "Nimbalyst README has a 'Mobile App' section: session dashboard, reply via text/voice, visual diff review (swipe to approve), push notifications. Repo includes packages/ios (Native iOS app, SwiftUI). Also has Android support (ANDROID_CHANGELOG.md, android-build.yml)."
        },
        "4_markdown_excalidraw_mockup_editing": {
          "status": "CONFIRMED",
          "evidence": "README lists built-in visual editors: Markdown, Mockups with annotations, Mermaid, Excalidraw, CSV, Data Models, Code with Monaco. Crystal README also mentions 'Rich markdown editing,' 'Excalidraw integration,' 'Visual mockup editing.'"
        },
        "5_successor_to_crystal": {
          "status": "CONFIRMED",
          "evidence": "stravu/crystal repo states: 'Crystal (formerly a multi-session AI code assistant manager) has been deprecated and replaced by Nimbalyst. Deprecated: February 2026.' Migration section links to https://github.com/Nimbalyst/nimbalyst."
        }
