          "claim": "https://www.intentapp.dev/",
          "actual": "Redirects to https://intent-by-augment.vercel.app/ — confirms Augment Code ownership"
        },
        "platform": {
          "status": "CONFIRMED",
          "claim": "macOS (Windows waitlist, Linux not announced)",
          "actual": "Website says 'Download for macOS.' Docs say 'Intent is a free desktop app.' No Windows or Linux download links visible. The claim about Windows waitlist/Linux not announced is consistent with what's visible — only macOS is offered."
        },
        "status": {
          "status": "CONFIRMED",
          "claim": "Public beta",
          "actual": "Augment Code pricing guide states: 'During the public beta period, Intent uses regular Augment credits at the same rate as the CLI or IDE extensions.'"
        },
        "pricing": {
          "status": "DISCREPANCY",
          "claim": "Augment credits ($0 trial / $20-$60/mo)",
          "actual": "Pricing tiers are: Trial (free), Indie $20/mo (40K credits), Standard $60/mo per developer (130K credits), Max $200/mo per developer (450K credits), Enterprise (custom). The claim's $20-$60/mo range covers Indie and Standard but omits the Max tier at $200/mo. BYOA (Claude Code, Codex, OpenCode) is free with no Augment subscription required."
        },
        "made_by": {
          "status": "CONFIRMED",
          "claim": "Augment Code",
          "actual": "Canonical URL is intent-by-augment.vercel.app. Docs link to augmentcode.com. Augment Code's own pricing guide covers Intent. The 'Auggie' agent is listed as a native provider."
        }
      },
      "feature_claims": {
        "1_spec_driven_coordination": {
          "status": "CONFIRMED",
          "evidence": "Docs: 'When you give a prompt, a coordinator agent generates a living spec document that captures assumptions, requirements, and design decisions.' Also: 'The Spec note is the planning document — the source of truth for what the workspace is trying to accomplish.'"
        },
        "2_coordinator_implementor_verifier": {
          "status": "CONFIRMED",
          "evidence": "Docs list specialists: Coordinator ('Plans work, breaks it into tasks, delegates to other agents'), Implementor ('Writes code for a specific task'), Verifier ('Reviews work against acceptance criteria'). Augment pricing guide confirms: 'Intent's default three-agent setup (Coordinator, Implementor, Verifier).'"
        },
        "3_byoa_claude_codex_opencode_auggie": {
          "status": "CONFIRMED",
          "evidence": "Docs: 'Works with Claude Code, Codex, or OpenCode as the underlying agent provider, so no Augment subscription is required.' Also lists Auggie as a native provider. Pricing guide: 'works with Auggie natively and also supports Claude Code, Codex, and OpenCode as agent providers.'"
        },
        "4_context_engine_mcp_server": {
          "status": "CONFIRMED",
          "evidence": "Docs: 'You can plug in any MCP server (including Augment's context engine for cross-repo awareness), and agents can use skills and custom tools through this system.' Pricing guide confirms 'the Context Engine MCP' as a pluggable MCP server."
        },
        "5_macos_desktop_app": {
          "status": "CONFIRMED",
          "evidence": "Website: 'Download for macOS.' Docs: 'Intent is a free desktop app that replaces the traditional IDE.' It is a native desktop application, not just a web app."
        }
      }
    },
    {
      "tool": "Conductor",
      "website": "https://www.conductor.build/",
      "github_repo": "No public app repo found; github.com/meltylabs has only a Starter-Project repo",
      "fields": {
        "website": {
          "status": "CONFIRMED",
          "claim": "https://www.conductor.build/",
          "actual": "Site is live and accessible."
        },
        "platform": {
          "status": "CONFIRMED",
          "claim": "macOS only",
          "actual": "Website: 'Run parallel coding agents on your Mac.' Docs: 'Get Conductor running on your Mac.' No Windows or Linux downloads. Multiple third-party sources confirm macOS only. One source notes Apple Silicon specifically."
        },
        "license": {
          "status": "CONFIRMED",
          "claim": "Closed source",
          "actual": "No public source repo for the app itself. The meltylabs GitHub org only has a Starter-Project (demo repo), not the app code. No open-source license mentioned anywhere."
        },
        "pricing": {
          "status": "CONFIRMED",
          "claim": "Free (BYO login)",
          "actual": "Multiple sources confirm: 'the app is free' and 'you bring your own API keys/subscriptions.' Docs reference configuring harnesses with your own provider auth (Claude Code, Codex, Cursor API keys). The app itself charges nothing."
        },
        "made_by": {
          "status": "CONFIRMED",
          "claim": "Melty Labs",
          "actual": "Multiple sources confirm 'Conductor by Melty Labs.' GitHub organization is github.com/meltylabs. Also identified as YC S24 company with $2.8M seed."
        }
      },
      "feature_claims": {
        "1_supports_claude_codex_cursor_opencode": {
          "status": "CONFIRMED",
          "evidence": "Docs: 'Conductor lets you run Claude Code, Codex, Cursor, and OpenCode in parallel.' Agent modes page confirms all four agents with model pickers and harness configuration."
        },
        "2_diff_first_review_workflow": {
          "status": "CONFIRMED",
          "evidence": "Workflow docs: 'Open the Diff Viewer with Command + Shift + D. Review changed files, leave comments, and ask an agent to address anything missing.' Full review→PR→merge→archive workflow described."
        },
        "3_is_it_free": {
          "status": "CONFIRMED",
          "evidence": "Third-party sources: 'the app itself is free — you bring your own API keys/subscriptions.' Docs reference BYO harness authentication for each agent provider."
        },
        "4_is_it_macos_only": {
          "status": "CONFIRMED",
          "evidence": "Website and docs consistently say 'on your Mac.' No mention of Windows or Linux builds or downloads."
        },
        "5_does_melty_labs_make_it": {
          "status": "CONFIRMED",
          "evidence": "GitHub org meltylabs (Starter-Project repo says 'starter project for Conductor, a macOS app'). Multiple third-party articles confirm 'Conductor by Melty Labs.'"
        }
      }
    }
  ]
}

